def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import heapq

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def compute_hv(pts):
        if len(pts) == 0:
            return 0.0
        return pg.hypervolume(np.array(pts)).compute(reference_point)

    selected = []
    remaining = list(range(n))

    if k == 0:
        return np.array([])

    # 计算每个点的初始贡献（单独贡献）
    initial_contributions = []
    hv_empty = 0.0

    for idx in remaining:
        hv_single = compute_hv([points[idx]])
        contrib = hv_single - hv_empty
        heapq.heappush(initial_contributions, (-contrib, idx))

    # 贪心选择，使用懒惰更新
    while len(selected) < k and initial_contributions:
        # 获取当前最大贡献的点
        neg_contrib, idx = heapq.heappop(initial_contributions)
        contrib = -neg_contrib

        # 重新计算实际贡献
        if selected:
            hv_current = compute_hv([points[i] for i in selected])
            hv_with = compute_hv([points[i] for i in selected] + [points[idx]])
            actual_contrib = hv_with - hv_current
        else:
            actual_contrib = contrib

        # 如果实际贡献与估计一致，选择该点
        if abs(actual_contrib - contrib) < 1e-10:
            selected.append(idx)
            remaining.remove(idx)
        else:
            # 否则重新插入队列
            heapq.heappush(initial_contributions, (-actual_contrib, idx))

    # 如果队列为空但还没选够k个点，从剩余点中随机选择
    if len(selected) < k:
        remaining = [i for i in range(n) if i not in selected]
        additional = min(k - len(selected), len(remaining))
        selected.extend(remaining[:additional])

    return np.array([points[i] for i in selected])

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random

    n, m = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def compute_hv(indices):
        if len(indices) == 0:
            return 0.0
        selected = points[list(indices)]
        hv = pg.hypervolume(selected)
        return hv.compute(reference_point)

    def greedy_initialization():
        current = set()
        for _ in range(k):
            best_idx = -1
            best_hv = -np.inf
            for i in range(n):
                if i not in current:
                    temp = current.copy()
                    temp.add(i)
                    hv = compute_hv(temp)
                    if hv > best_hv:
                        best_hv = hv
                        best_idx = i
            current.add(best_idx)
        return current

    current_set = greedy_initialization()
    current_hv = compute_hv(current_set)

    max_cycles = 50
    for cycle in range(max_cycles):
        improved = False

        removal_candidates = list(current_set)
        random.shuffle(removal_candidates)

        for r in removal_candidates[:min(3, k)]:
            temp_set = current_set.copy()
            temp_set.remove(r)

            best_add = -1
            best_hv_add = -np.inf
            for i in range(n):
                if i not in temp_set:
                    test_set = temp_set.copy()
                    test_set.add(i)
                    hv = compute_hv(test_set)
                    if hv > best_hv_add:
                        best_hv_add = hv
                        best_add = i

            if best_add != -1:
                temp_set.add(best_add)
                new_hv = compute_hv(temp_set)

                if new_hv > current_hv:
                    current_set = temp_set
                    current_hv = new_hv
                    improved = True
                    break

        if not improved:
            break

    return points[list(current_set)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points
